window.addEventListener('DOMContentLoaded',()=>{const list=document.getElementById('related-posts-list');const wrapper=document.querySelector('.related-posts');if(!list)return;const label=list.getAttribute('data-label');if(!label){if(wrapper)wrapper.style.display='none';return;}
const currentUrl=window.location.href.split(/[?#]/)[0];window.loadRelatedPosts=json=>{let html='';if(json&&json.feed&&json.feed.entry){const posts=json.feed.entry;let count=0;for(let i=0;i<posts.length;i++){const title=posts[i].title.$t;let url='';for(let j=0;j<posts[i].link.length;j++){if(posts[i].link[j].rel==='alternate'){url=posts[i].link[j].href;break;}}
if(url.split(/[?#]/)[0]===currentUrl)continue;html+='<li><a href="'+url+'">'+title+'</a></li>';count++;if(count>=3)break;}}
if(html){list.innerHTML=html;}else{if(wrapper)wrapper.style.display='none';}};const script=document.createElement('script');script.src='/feeds/posts/default/-/'+encodeURIComponent(label)+'?alt=json-in-script&callback=loadRelatedPosts&max-results=6';document.body.appendChild(script);});
