(function(){const PUNCT=/(?<=[，。；！？：、:])/;const wrap=function(el){if(!el)return;const parts=el.textContent.split(PUNCT).filter(Boolean);if(parts.length<=1)return;el.innerHTML='';parts.forEach(function(part){const chunk=document.createElement('span');chunk.style.cssText='display:inline-block;white-space:nowrap;';chunk.textContent=part;el.appendChild(chunk);});};wrap(document.querySelector('.header-logo-link > span'));document.querySelectorAll('h2.post-title').forEach(function(h2){wrap(h2.querySelector('a')||h2);});})();(function(){const nav=document.querySelector('nav.main-nav');if(!nav)return;const norm=function(p){return(decodeURIComponent(p).replace(/\/+$/,''))||'/';};const here=norm(location.pathname);const links=nav.querySelectorAll('a');let active=null;links.forEach(function(a){let p;try{p=norm(new URL(a.href,location.origin).pathname);}catch(e){return;}
if(p===here)active=a;});if(!active&&here==='/'&&links[0])active=links[0];if(active)active.classList.add('is-active');})();(function(){const nav=document.querySelector('nav.main-nav');if(!nav)return;const check=function(){nav.classList.toggle('is-scrolling',nav.scrollWidth>nav.clientWidth+1);};check();if('ResizeObserver'in window){new ResizeObserver(check).observe(nav);}else{window.addEventListener('resize',check);}
nav.addEventListener('wheel',function(e){if(!nav.classList.contains('is-scrolling'))return;if(Math.abs(e.deltaY)<=Math.abs(e.deltaX))return;const dir=e.deltaY>0?1:-1;const atEnd=(dir>0&&nav.scrollLeft>=nav.scrollWidth-nav.clientWidth-1)||(dir<0&&nav.scrollLeft<=0);if(atEnd)return;e.preventDefault();nav.scrollLeft+=e.deltaY;},{passive:false});})();(function(){if(window.innerWidth<1024)return;const postBody=document.querySelector('.post-body.full-content');if(!postBody)return;const parseDate=function(){const meta=document.querySelector('.post-meta');if(meta){for(let i=0;i<meta.childNodes.length;i++){const n=meta.childNodes[i];if(n.nodeType===3&&n.textContent.trim()){const d=new Date(n.textContent.trim());if(!isNaN(d.getTime()))return d;break;}}}
const sibling=document.querySelector('.date-header');if(sibling){const ds=new Date(sibling.textContent.trim());if(!isNaN(ds.getTime()))return ds;}
const m=window.location.pathname.match(/\/(\d{4})\/(\d{2})\//);if(m)return new Date(parseInt(m[1],10),parseInt(m[2],10)-1,1);return null;};const estimateReadMinutes=function(text){if(!text)return 1;const cjk=(text.match(/[\u4e00-\u9fff]/g)||[]).length;const noCjk=text.replace(/[\u4e00-\u9fff]/g,' ');const enWords=(noCjk.match(/[A-Za-z0-9]+/g)||[]).length;const minutes=cjk/350+enWords/220;return Math.max(1,Math.round(minutes));};const EN_MONTHS=['JANUARY','FEBRUARY','MARCH','APRIL','MAY','JUNE','JULY','AUGUST','SEPTEMBER','OCTOBER','NOVEMBER','DECEMBER'];const ZH_MONTHS=['一月','二月','三月','四月','五月','六月','七月','八月','九月','十月','十一月','十二月'];const ZH_DIGITS=['〇','一','二','三','四','五','六','七','八','九'];const toZhYear=function(year){return String(year).split('').map(function(d){return ZH_DIGITS[parseInt(d,10)];}).join('');};const toZhMinutes=function(n){if(n<10)return ZH_DIGITS[n];if(n>=100)return String(n);const tens=Math.floor(n/10);const ones=n%10;const tensStr=tens===1?'十':ZH_DIGITS[tens]+'十';return ones===0?tensStr:tensStr+ZH_DIGITS[ones];};const rails=[];const d=parseDate();if(d){const dateRail=document.createElement('div');dateRail.className='desktop-date-rail';dateRail.setAttribute('aria-hidden','true');dateRail.innerHTML='<span class="lang-zh">'+toZhYear(d.getFullYear())+'·'+ZH_MONTHS[d.getMonth()]+'</span>'+'<span class="lang-en">'+EN_MONTHS[d.getMonth()]+' · '+d.getFullYear()+'</span>';document.body.appendChild(dateRail);rails.push(dateRail);}
