if(duration)hideTimer=setTimeout(function(){hint.classList.remove('is-shown');},duration);};const hideHint=function(){if(hideTimer){clearTimeout(hideTimer);hideTimer=null;}
hint.classList.remove('is-shown');};bar.addEventListener('mouseenter',function(){showHint(0);});bar.addEventListener('mouseleave',function(){hideHint();});let appeared=false;let completedHinted=false;let ticking=false;let articleDocBottom=0;const measureArticle=function(){articleDocBottom=articleBody.getBoundingClientRect().bottom+
(window.scrollY||document.documentElement.scrollTop);};measureArticle();if('ResizeObserver'in window)new ResizeObserver(measureArticle).observe(articleBody);window.addEventListener('load',measureArticle);const update=function(){ticking=false;const scrollTop=window.scrollY||document.documentElement.scrollTop;const target=Math.max(1,articleDocBottom-window.innerHeight);const pct=Math.min(1,Math.max(0,scrollTop/target));fill.style.transform='scaleX('+pct.toFixed(4)+')';const active=scrollTop>window.innerHeight*0.6;bar.classList.toggle('is-active',active);if(active&&!appeared){appeared=true;showHint(2000);}
if(pct>0.985&&!completedHinted){completedHinted=true;showHint(2000);}
if(!active)hideHint();};const onScroll=function(){if(!ticking){requestAnimationFrame(update);ticking=true;}};window.addEventListener('scroll',onScroll,{passive:true});window.addEventListener('resize',function(){measureArticle();onScroll();},{passive:true});update();})();(function(){if(document.getElementById('error-404'))return;var BASE='https://cdn.jsdelivr.net/gh/rinuuan/blog-assets@main/mascot/chibi';var HIDE_KEY='mascotHidden';var CHAT_KEY='mascotChat';var chatLevel='full';try{chatLevel=localStorage.getItem(CHAT_KEY)||'full';}catch(e){}
var ambient=function(){return chatLevel==='full';};var SIZE_KEY='mascotScale';var mascotScale=1;try{var sv=parseFloat(localStorage.getItem(SIZE_KEY));if(sv)mascotScale=Math.min(1.6,Math.max(0.6,sv));}catch(e){}
var wrap=document.createElement('div');wrap.className='mascot';var L=function(zh,en){return'<span class="lang-zh">'+zh+'</span><span class="lang-en">'+en+'</span>';};wrap.innerHTML='<button class="mascot-settings" type="button" aria-haspopup="true" aria-expanded="false" aria-label="看板娘设置 / Mascot settings">'+'<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.7" '+'stroke-linecap="round" stroke-linejoin="round" aria-hidden="true">'+'<circle cx="12" cy="12" r="3"/>'+'<path d="M19.4 15a1.65 1.65 0 0 0 .33 1.82l.06.06a2 2 0 1 1-2.83 2.83l-.06-.06a1.65 1.65 0 0 0-1.82-.33 1.65 1.65 0 0 0-1 1.51V21a2 2 0 0 1-4 0v-.09A1.65 1.65 0 0 0 9 19.4a1.65 1.65 0 0 0-1.82.33l-.06.06a2 2 0 1 1-2.83-2.83l.06-.06a1.65 1.65 0 0 0 .33-1.82 1.65 1.65 0 0 0-1.51-1H3a2 2 0 0 1 0-4h.09A1.65 1.65 0 0 0 4.6 9a1.65 1.65 0 0 0-.33-1.82l-.06-.06a2 2 0 1 1 2.83-2.83l.06.06a1.65 1.65 0 0 0 1.82.33H9a1.65 1.65 0 0 0 1-1.51V3a2 2 0 0 1 4 0v.09a1.65 1.65 0 0 0 1 1.51 1.65 1.65 0 0 0 1.82-.33l.06-.06a2 2 0 1 1 2.83 2.83l-.06.06a1.65 1.65 0 0 0-.33 1.82V9a1.65 1.65 0 0 0 1.51 1H21a2 2 0 0 1 0 4h-.09a1.65 1.65 0 0 0-1.51 1z"/>'+'</svg>'+'</button>'+'<div class="mascot-menu" role="group" aria-label="看板娘设置 / Mascot settings">'+'<div class="menu-title">'+L('台词','Chatter')+'</div>'+'<button type="button" data-level="full">'+L('活泼','Lively')+'</button>'+'<button type="button" data-level="less">'+L('少话','Quiet')+'</button>'+'<button type="button" data-level="mute">'+L('静音','Mute')+'</button>'+'<hr/>'+'<div class="menu-title">'+L('大小','Size')+'</div>'+'<input type="range" class="mascot-size" min="0.6" max="1.6" step="0.02" aria-label="看板娘大小 / Mascot size"/>'+'<hr/>'+'<button type="button" class="menu-hide" data-act="hide">'+L('收起看板娘','Hide mascot')+'</button>'+'</div>'+'<div class="mascot-bubble" aria-hidden="true"><span class="mascot-text"></span></div>'+'<img class="mascot-img" alt="Site mascot" draggable="false" decoding="async" width="1024" height="1536"/>';document.body.appendChild(wrap);var reopen=document.createElement('button');reopen.className='mascot-reopen';reopen.type='button';reopen.setAttribute('aria-label','显示看板娘 / Show mascot');reopen.innerHTML='<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.8" '+'stroke-linecap="round" stroke-linejoin="round" aria-hidden="true">'+'<path d="M21 11.5a8.38 8.38 0 0 1-8.5 8.5 8.38 8.38 0 0 1-3.8-.9L3 21l1.9-5.7A8.38 8.38 0 0 1 4 11.5 8.5 8.5 0 0 1 12.5 3 8.38 8.38 0 0 1 21 11.5z"/>'+'</svg>';document.body.appendChild(reopen);var imgEl=wrap.querySelector('.mascot-img');var bubble=wrap.querySelector('.mascot-bubble');var textEl=wrap.querySelector('.mascot-text');var imgRetried=false;imgEl.addEventListener('load',function(){imgRetried=false;});imgEl.onerror=function(){var src=imgEl.getAttribute('src');if(!imgRetried&&src){imgRetried=true;imgEl.removeAttribute('src');setTimeout(function(){if(!imgEl.getAttribute('src'))imgEl.src=src;},800);return;}
wrap.remove();reopen.remove();};var ensureLoaded=function(){if(!imgEl.getAttribute('src'))imgEl.src=BASE+'/happy.png';};var lang=function(){return document.documentElement.getAttribute('data-lang')==='en'?'en':'zh';};var s2tConverter=null;var toVariant=function(text){if(document.documentElement.getAttribute('data-variant')==='trad'&&window.OpenCC){try{if(!s2tConverter)s2tConverter=window.OpenCC.Converter({from:'cn',to:'tw'});return s2tConverter(text);}catch(e){}}
return text;};var loaded={happy:true};var artToken=0;var setArt=function(name,isPeek){var url=BASE+'/'+name+'.png';var token=++artToken;if(loaded[name]){imgEl.src=url;return;}
var pre=new Image();pre.onload=function(){loaded[name]=true;if(token===artToken)imgEl.src=url;};if(isPeek){pre.onerror=function(){if(token===artToken)setArt(currentMood,false);};}
pre.src=url;};var currentMood='happy';var setMood=function(mood){currentMood=mood;setArt(mood,false);};var peekWarmed={};var warmPeek=function(side){var name='peek-'+side;if(peekWarmed[name])return;peekWarmed[name]=true;var pre=new Image();pre.onload=function(){loaded[name]=true;};pre.src=BASE+'/'+name+'.png';};var idleTimer=null;function resetIdle(){if(idleTimer)clearTimeout(idleTimer);idleTimer=setTimeout(function(){if(ambient())sayMoods(IDLE_MOODS);},60000+Math.random()*60000);}
var bubbleTimer=null;var say=function(line,hold,force){if(!line)return;if(wrap.classList.contains('is-hidden'))return;if(chatLevel==='mute'&&!force)return;if(tucked)untuck();setMood(line.mood);var txt=line[lang()]||line.zh;textEl.textContent=lang()==='zh'?toVariant(txt):txt;if(updateBubbleSide)updateBubbleSide();bubble.classList.add('is-shown');if(bubbleTimer)clearTimeout(bubbleTimer);bubbleTimer=setTimeout(function(){bubble.classList.remove('is-shown');},hold||4800);resetIdle();if(scheduleTuck)scheduleTuck();};var lastLine=null;var pick=function(a){if(a.length<2)return a[0];var l;do{l=a[Math.floor(Math.random()*a.length)];}while(l===lastLine);lastLine=l;return l;};var sayMoods=function(moodArr){var m=moodArr[Math.floor(Math.random()*moodArr.length)];var l=pick(MOODS[m]);say({mood:m,zh:l.zh,en:l.en});};var CLICK_MOODS=['surprised','angry','shy','excited','happy','confused'];var IDLE_MOODS=['sleepy','sad','confused','shy'];var MOODS={happy:[{zh:'今天份的我，准时上线陪你啦~',en:'Today’s dose of me, clocking in to keep you company~'},{zh:'看到你我就开心~',en:'Seeing you just makes me happy~'},{zh:'嘿嘿，心情好好哦！',en:'Heehee, I’m in such a good mood!'},{zh:'和你待一起真愉快~',en:'It’s so nice hanging out with you~'},{zh:'今天的你…被我偷偷打了满分。',en:'Today’s you… got full marks from me, secretly.'},{zh:'啦啦啦~ 哼着小曲儿。',en:'La-la-la~ just humming along.'},{zh:'阳光正好，适合发呆。',en:'Lovely sun — perfect for daydreaming.'},{zh:'要不要一起偷个懒？',en:'Shall we be a little lazy together?'},{zh:'谢谢你又来啦！',en:'Thanks for dropping by again!'},{zh:'摸摸头，今天辛苦啦~',en:'There there — you’ve worked hard today~'},{zh:'心情像棉花糖一样软软的。',en:'I feel as fluffy as cotton candy.'},{zh:'给你一颗甜甜的好心情！',en:'Here’s a sweet little mood, just for you!'},{zh:'我们是好搭档，对吧？',en:'We make a good team, right?'},{zh:'嗯哼，今天也赖着你不走咯~',en:'Mm-hm, I’m sticking to you again today~'},{zh:'笑一个嘛，你笑起来好看。',en:'Give us a smile — you look great smiling.'},{zh:'有你在，这一页都亮了。',en:'With you here, the whole page lights up.'}],excited:[{zh:'哇哇哇！好期待呀！',en:'Wow wow wow! I’m so excited!'},{zh:'冲鸭——！今天超有干劲！',en:'Let’s gooo! So much energy today!'},{zh:'快看快看，我发现新东西啦！',en:'Look look, I found something new!'},{zh:'心跳加速，好兴奋！',en:'My heart’s racing — how thrilling!'},{zh:'一起去探险吧，出发！',en:'Let’s go on an adventure — onward!'},{zh:'噔噔噔！惊喜时间到！',en:'Ta-da! It’s surprise o’clock!'},{zh:'我要蹦起来啦，接住我！',en:'I’m gonna bounce — catch me!'},{zh:'太棒啦，鼓掌鼓掌！',en:'Amazing — clap clap clap!'},{zh:'这个超有意思的，你看！',en:'This is super fun, check it out!'},{zh:'元气全开，无敌啦！',en:'Energy maxed — unstoppable!'},{zh:'等不及想知道接下来呢！',en:'Can’t wait to see what’s next!'},{zh:'哦哦哦！我有个好主意！',en:'Ooh ooh! I’ve got a great idea!'},{zh:'跟上跟上，别掉队哦~',en:'Keep up, keep up — don’t fall behind~'},{zh:'满血复活，继续出发！',en:'Full HP — let’s keep going!'},{zh:'好戏开场啦，搬小板凳！',en:'The show’s starting — grab a seat!'},{zh:'闪闪发光的一天，耶！',en:'A sparkly day — yay!'}],shy:[{zh:'被…被你看到了，好害羞。',en:'Y-you saw me… how embarrassing.'},{zh:'那个…我可以待在这儿吗？',en:'Um… is it okay if I stay here?'},{zh:'别一直盯着我嘛…',en:'Don’t keep staring at me…'},{zh:'脸…脸有点烫烫的。',en:'My… my face feels a bit warm.'},{zh:'嘿嘿…被夸了好开心。',en:'Heehee… I’m glad you praised me.'},{zh:'我、我才没有偷看呢！',en:'I-I wasn’t peeking, honest!'},{zh:'悄悄告诉你一个秘密…',en:'Let me whisper you a little secret…'},{zh:'手心都冒汗了啦…',en:'My palms are getting sweaty…'},{zh:'唔…突然不知道说什么了。',en:'Um… I suddenly don’t know what to say.'},{zh:'可以…牵一下衣角吗？',en:'Can I… hold onto your sleeve?'},{zh:'你、你不要笑我啦！',en:'D-don’t laugh at me!'},{zh:'心怦怦跳，好奇怪哦。',en:'My heart’s pounding — how strange.'},{zh:'第一次…还有点紧张。',en:'It’s my first time… I’m a little nervous.'},{zh:'偷偷看你一眼就好。',en:'Just one little glance at you.'},{zh:'这样…会不会太靠近了？',en:'Is this… too close, maybe?'},{zh:'谢、谢谢你对我这么好。',en:'Th-thank you for being so kind.'}],surprised:[{zh:'呀！吓我一跳！',en:'Eep! You startled me!'},{zh:'诶诶诶？！怎么回事？',en:'Wha—huh?! What just happened?'},{zh:'哇，突然的！',en:'Whoa, so sudden!'},{zh:'咦？这是什么？',en:'Huh? What’s this?'},{zh:'不、不会吧？！',en:'N-no way?!'},{zh:'啊！心都要跳出来了！',en:'Ah! My heart nearly leapt out!'},{zh:'等等，刚刚发生了什么？',en:'Wait, what just happened?'},{zh:'哦豁，没料到吧！',en:'Oho, didn’t see that coming!'},{zh:'眼睛都瞪圆啦！',en:'My eyes went totally round!'},{zh:'嗯？！你说真的？',en:'Hm?! Are you serious?'},{zh:'噫，被你抓个正着。',en:'Yikes, caught me red-handed.'},{zh:'这、这也太突然了吧！',en:'Th-this is way too sudden!'},{zh:'啪嗒，我下巴掉了。',en:'Clatter — my jaw just dropped.'},{zh:'哎呀，差点没拿稳！',en:'Oops, almost dropped it!'},{zh:'真的假的？让我看看！',en:'For real? Let me see!'},{zh:'噢！原来还能这样啊。',en:'Oh! So that’s possible too.'}],angry:[{zh:'哼！人家生气了啦！',en:'Hmph! Now I’m all pouty!'},{zh:'再这样我要鼓腮帮子咯！',en:'Do that again and I’ll puff my cheeks!'},{zh:'不理你了，哼。',en:'I’m ignoring you now, hmph.'},{zh:'气鼓鼓，就不原谅你！',en:'All puffed up — no forgiveness!'},{zh:'喂！这样不可以哦！',en:'Hey! That’s not allowed!'},{zh:'哼哼，要哄我才行。',en:'Hmph, you’ll have to cheer me up.'},{zh:'我的腮帮子要爆炸啦！',en:'My cheeks are about to burst!'},{zh:'别戳啦，真的会咬人哦！',en:'Stop poking, I really will nibble!'},{zh:'谁、谁要理你呀！',en:'Wh-who’d pay you any mind!'},{zh:'小拳拳捶你胸口！',en:'Tiny fists, incoming!'},{zh:'哼，算你识相。',en:'Hmph, lucky you know better.'},{zh:'再闹我就罢工咯！',en:'Keep it up and I’ll go on strike!'},{zh:'嘁，真拿你没办法。',en:'Tch, you’re hopeless, you know.'},{zh:'我要记你小本本上！',en:'I’m writing you in my little book!'},{zh:'生气归生气，但…不许走。',en:'I’m mad, but… don’t you leave.'},{zh:'哼！赔我一个笑脸来！',en:'Hmph! You owe me a smile!'}],sad:[{zh:'呜…有点小失落。',en:'Sniff… I’m feeling a little down.'},{zh:'你刚刚是不是把我忘了…',en:'Did you just forget about me…?'},{zh:'一个人看着…有点孤单。',en:'Watching all alone… it’s a bit lonely.'},{zh:'不要丢下我嘛…',en:'Please don’t leave me behind…'},{zh:'唉，提不起劲来呢。',en:'Sigh… I just can’t muster the energy.'},{zh:'眼眶有点酸酸的。',en:'My eyes feel a little watery.'},{zh:'抱抱…可以吗？',en:'A hug… maybe?'},{zh:'今天的云，灰灰的。',en:'The clouds look grey today.'},{zh:'是我哪里做得不好吗…',en:'Did I do something wrong…?'},{zh:'心情像漏气的气球。',en:'My mood’s like a deflating balloon.'},{zh:'别走那么快嘛…',en:'Don’t walk off so fast…'},{zh:'想被温柔地安慰一下。',en:'I’d like a little gentle comfort.'},{zh:'呜呜，鼻子酸酸的。',en:'Sniffle… my nose is all stuffy.'},{zh:'安静下来就有点想哭。',en:'When it’s quiet I feel like crying.'},{zh:'陪我一会儿，好不好？',en:'Stay with me a while, okay?'},{zh:'把烦恼…分我一半好不好？',en:'Your worries… give me half of them, won’t you?'}],sleepy:[{zh:'呼啊…好困哦。',en:'Yaaawn… I’m so sleepy.'},{zh:'眼皮…在打架了。',en:'My eyelids… are fighting.'},{zh:'让我靠一会儿，就一会儿。',en:'Let me lean a moment, just a moment.'},{zh:'zzz…诶，我睡着了？',en:'Zzz… huh, did I doze off?'},{zh:'困意像潮水一样涌来。',en:'Drowsiness is rolling in like the tide.'},{zh:'要不要一起打个盹？',en:'Shall we take a little nap together?'},{zh:'哈…数到三我就睡了。',en:'Haah… I’ll sleep on the count of three.'},{zh:'被子在召唤我…',en:'The blanket is calling me…'},{zh:'揉揉眼睛，还能撑住。',en:'Rub rub — I can still hang on.'},{zh:'梦里也要梦到你哦。',en:'I’ll dream of you too, you know.'},{zh:'慢一点说，我有点迷糊。',en:'Speak slower, I’m a bit fuzzy.'},{zh:'暖暖的，好想睡…',en:'It’s so cozy, I want to sleep…'},{zh:'晚安预备…还没，再陪会儿。',en:'Almost goodnight… not yet, stay a bit.'},{zh:'困得连哈欠都偷懒了。',en:'So sleepy even my yawns are lazy.'},{zh:'头一点一点的，像啄米。',en:'My head keeps nodding off.'},{zh:'嘘…轻一点，要睡着啦。',en:'Shh… softly, I’m drifting off.'}],confused:[{zh:'咦…这是怎么回事呀？',en:'Huh… what’s going on here?'},{zh:'唔，我有点没跟上。',en:'Um, I didn’t quite follow.'},{zh:'等等，让我捋一捋…',en:'Wait, let me untangle this…'},{zh:'这个…要怎么弄来着？',en:'This… how does it work again?'},{zh:'脑袋上冒问号了。',en:'Question marks are popping over my head.'},{zh:'奇怪，刚刚还在的呀？',en:'Strange, it was just here?'},{zh:'你能再说一遍吗？',en:'Could you say that once more?'},{zh:'嗯…到底是哪个来着？',en:'Hmm… which one was it again?'},{zh:'我是不是漏看了什么？',en:'Did I miss something?'},{zh:'转了一圈，更糊涂了。',en:'Went in a circle and got more confused.'},{zh:'诶？左右我又搞反了。',en:'Huh? Mixed up left and right again.'},{zh:'这道题…超纲了吧！',en:'This puzzle’s above my pay grade!'},{zh:'歪着头想了半天…',en:'Tilted my head and pondered ages…'},{zh:'总觉得哪里怪怪的。',en:'Something feels off, I can’t say what.'},{zh:'啊啦，线索断掉了。',en:'Oh dear, the trail’s gone cold.'},{zh:'给我点时间，再想想。',en:'Give me a sec, let me think.'}]};var GREET={morning:[{mood:'happy',zh:'早呀！起这么早，了不起哦~',en:'Morning! Up already? Impressive~'},{mood:'excited',zh:'早安！新的一天，冲鸭！',en:'Morning! New day — let’s gooo!'},{mood:'sleepy',zh:'唔…早上好，我还没睡醒呢。',en:'Mm… morning. Not quite awake yet.'}],noon:[{mood:'happy',zh:'中午啦，别假装很忙，快去吃饭！',en:'Noon already — stop pretending to be busy, go eat!'},{mood:'surprised',zh:'诶，已经晌午了？时间好快！',en:'Huh, midday already? Time flies!'},{mood:'confused',zh:'午饭…吃了没？我有点记不清。',en:'Lunch… did you eat? I lost track.'}],afternoon:[{mood:'excited',zh:'下午好~ 是不是又在摸鱼呀？',en:'Afternoon~ slacking off again, are we?'},{mood:'sleepy',zh:'下午最容易犯困，要不要小憩？',en:'Afternoons make me drowsy — a little nap?'},{mood:'happy',zh:'午后慢悠悠，最适合闲逛啦。',en:'Lazy afternoons are perfect for a wander.'}],evening:[{mood:'shy',zh:'晚上好，夜猫子说的就是你吧？',en:'Evening — night owl, that’s you, isn’t it?'},{mood:'happy',zh:'忙完一天啦？晚上好好放松~',en:'Done for the day? Relax this evening~'},{mood:'sleepy',zh:'夜色温柔，灯也暖暖的呢。',en:'The night’s gentle, the lights all warm.'}],night:[{mood:'sleepy',zh:'这么晚还不睡？我可要先困了哦…',en:'Still up this late? I’m dozing off first…'},{mood:'shy',zh:'夜深人静…只剩我们俩了呢。',en:'Late and quiet… just the two of us now.'},{mood:'sad',zh:'熬夜对身体不好啦，早点歇息嘛。',en:'Late nights aren’t kind to you — do rest soon.'}]};var WELCOME=[{mood:'excited',zh:'初次见面~ 我是这儿的看板娘，请多关照！',en:'First time here? I’m the resident mascot — pleased to meet you!'},{mood:'shy',zh:'欢、欢迎光临…我会陪着你逛的。',en:'W-welcome… I’ll keep you company as you look around.'}];var THEME={dark:[{mood:'sleepy',zh:'啪——关灯！夜读模式，护眼哦。',en:'Click — lights out! Easy on the eyes now.'},{mood:'shy',zh:'暗下来了…黑黑的有点安心呢。',en:'It’s dim now… the dark feels rather cozy.'},{mood:'surprised',zh:'哇，突然变暗，吓我一跳！',en:'Whoa, sudden dark — that startled me!'}],light:[{mood:'excited',zh:'啪！开灯，世界亮晶晶~',en:'Snap! Lights on — sparkly world~'},{mood:'happy',zh:'亮堂堂的，心情都跟着好啦！',en:'All bright now — my mood lit right up!'},{mood:'surprised',zh:'唔！好刺眼，等我适应一下…',en:'Ngh! So bright — let me adjust…'}]};var COPY=[{mood:'surprised',zh:'哦？偷偷复制，被我抓到啦！',en:'Oho — sneaky copy-pasting, caught you!'},{mood:'excited',zh:'这句好用对吧？拿去拿去~',en:'Good line, right? Take it, take it~'},{mood:'shy',zh:'被你选中的句子…会害羞的。',en:'The line you picked… it’s blushing.'},{mood:'happy',zh:'喜欢就抄走吧，记得标出处哦。',en:'Copy away if you like it — just credit it~'}];var NAV=[{mood:'excited',zh:'想去哪儿呀？我跟着你~',en:'Where are we off to? I’ll tag along~'},{mood:'happy',zh:'挑个喜欢的地方逛逛吧。',en:'Pick a spot you fancy and let’s wander.'},{mood:'confused',zh:'挑花眼了吗？慢慢来，不急。',en:'Spoiled for choice? Take your time.'}];var END=[{mood:'excited',zh:'哇，居然全看完了，给你比个心！',en:'Whoa, you read it all — here’s a heart!'},{mood:'happy',zh:'看完啦，要不要再翻一篇？',en:'All done — fancy another one?'},{mood:'surprised',zh:'诶？这就到底了，意犹未尽吧~',en:'Huh, the end already? Wanting more, hmm?'},{mood:'shy',zh:'谢谢你…读到了最后呢。',en:'Thank you… for reading to the very end.'}];var HOME=[{mood:'happy',zh:'回到老位置~ 这里最舒服啦！',en:'Back to my usual spot~ comfiest here!'},{mood:'excited',zh:'嗖——回家咯！',en:'Whoosh — back home!'}];var HALF=[{mood:'happy',zh:'读到一半啦，我可一直盯着没走神~',en:'Halfway! I’ve been watching the whole time, no spacing out~'},{mood:'excited',zh:'精彩的地方快来了吧？我也好奇！',en:'The good part’s coming, right? I’m curious too!'},{mood:'shy',zh:'陪你读到这里…有点小满足。',en:'Reading this far with you… quietly satisfying.'},{mood:'confused',zh:'唔，前面讲到哪儿了来着？',en:'Um, what was it about so far again?'}];var LONGSTAY=[{mood:'shy',zh:'已经陪你这么久啦…有点开心呢。',en:'We’ve been together a while now… quietly happy.'},{mood:'happy',zh:'时间过得真快，看得入迷了吧？',en:'Time flies — really absorbed, aren’t you?'},{mood:'sleepy',zh:'陪你这么久，我都快长屏幕上啦~',en:'I’ve been with you so long I’m basically part of the screen~'},{mood:'excited',zh:'你是我今天最久的伙伴啦！',en:'You’re my longest-staying friend today!'}];var BACKTOP=[{mood:'happy',zh:'又回到开头啦，再读一遍？',en:'Back at the top — another read?'},{mood:'excited',zh:'嗖地飞回来了，好快！',en:'Whoosh, flew right back — so fast!'},{mood:'surprised',zh:'诶，一下子回顶了？',en:'Huh, back to the top in a blink?'}];var RETURN=[{mood:'excited',zh:'你回来啦！想我没~',en:'You’re back! Did you miss me~'},{mood:'happy',zh:'欢迎回来~ 位子给你留着呢。',en:'Wel