document.addEventListener("DOMContentLoaded",()=>{const root=document.documentElement;const yearEl=document.getElementById("current-year");if(yearEl)yearEl.textContent=new Date().getFullYear();const fadeTargets=document.querySelectorAll('.site-header, nav.main-nav, #main-content, .site-footer, .top-actions');const triggerContentFade=callback=>{fadeTargets.forEach(el=>el.classList.add('content-fade-out'));setTimeout(()=>{callback();setTimeout(()=>fadeTargets.forEach(el=>el.classList.remove('content-fade-out')),50);},350);};const themeToggle=document.getElementById("theme-toggle");if(themeToggle){themeToggle.addEventListener("click",()=>{const newTheme=root.getAttribute("data-theme")==="dark"?"light":"dark";root.setAttribute("data-theme",newTheme);localStorage.setItem("theme",newTheme);});}
const langToggle=document.getElementById("lang-toggle");if(langToggle){langToggle.addEventListener("click",()=>{triggerContentFade(()=>{const newLang=root.getAttribute("data-lang")==="zh"?"en":"zh";root.setAttribute("data-lang",newLang);localStorage.setItem("lang",newLang);});});}
const ignoreTags=new Set(["SCRIPT","STYLE","NOSCRIPT","IFRAME","CODE"]);const walkTextNodes=(node,applyConversion)=>{const walker=document.createTreeWalker(node,NodeFilter.SHOW_TEXT,{acceptNode:n=>ignoreTags.has(n.parentNode.nodeName)?NodeFilter.FILTER_REJECT:NodeFilter.FILTER_ACCEPT},false);let currentNode;while(currentNode=walker.nextNode()){if(currentNode.nodeValue.trim())currentNode.nodeValue=applyConversion(currentNode.nodeValue);}};const loadOpenCC=(targetVariant,callback)=>{const executeConversion=()=>{const converter=window.OpenCC.Converter({from:targetVariant==="simp"?"tw":"cn",to:targetVariant==="simp"?"cn":"tw"});walkTextNodes(document.body,converter);root.setAttribute("data-variant",targetVariant);localStorage.setItem("variant",targetVariant);if(callback)callback();};if(window.OpenCC){executeConversion();}else{const script=document.createElement("script");script.src="https://cdn.jsdelivr.net/npm/opencc-js@1.0.5/dist/umd/full.js";script.async=true;script.defer=true;script.onload=executeConversion;document.head.appendChild(script);}};let s2tConv=null;window.__rinuanToVariant=subtree=>{if(!subtree||root.getAttribute("data-variant")!=="trad"||!window.OpenCC)return;try{if(!s2tConv)s2tConv=window.OpenCC.Converter({from:"cn",to:"tw"});walkTextNodes(subtree,s2tConv);}catch(e){}};if(root.getAttribute("data-variant")==="trad"){setTimeout(()=>loadOpenCC("trad"),200);}
const variantToggle=document.getElementById("variant-toggle");if(variantToggle){variantToggle.addEventListener("click",()=>{triggerContentFade(()=>loadOpenCC(root.getAttribute("data-variant")==="simp"?"trad":"simp"));});}});
