window.addEventListener("DOMContentLoaded",()=>{const isFullPostView=!!document.querySelector('.post-body.full-content');function adjustPostTypography(root){root.querySelectorAll('.post-outer').forEach(post=>{const body=post.querySelector('.post-body');if(!body)return;const tagNodes=post.querySelectorAll('.post-tag, .hidden-tag');const tags=Array.from(tagNodes).map(t=>{const raw=t.getAttribute('data-raw-tag')||t.textContent;return raw.trim().toLowerCase();});const isEnglish=tags.includes('english')||tags.includes('en');if(isEnglish){body.style.cssText+='line-height:1.7;text-align:left;hyphens:auto;-webkit-hyphens:auto;word-spacing:0.05em;';body.setAttribute('lang','en');}else{body.style.cssText+='line-height:2.2;text-align:justify;hyphens:none;-webkit-hyphens:none;word-spacing:normal;';body.setAttribute('lang','zh-Hans');}
const title=post.querySelector('.post-title');if(title)title.setAttribute('lang',isEnglish?'en':'zh-Hans');body.querySelectorAll('img').forEach((img,idx)=>{if(!img.hasAttribute('loading')){img.setAttribute('loading',idx===0&&isFullPostView?'eager':'lazy');}
if(!img.hasAttribute('decoding'))img.setAttribute('decoding','async');});});}
adjustPostTypography(document);const navDictionary={"Home":{zh:"首页",en:"Home"},"首页":{zh:"首页",en:"Home"},"首頁":{zh:"首页",en:"Home"},"English":{zh:"英文",en:"English"},"中文":{zh:"中文",en:"Chinese"},"Novels":{zh:"小说",en:"Novels"},"小说":{zh:"小说",en:"Novels"},"Poems":{zh:"诗歌",en:"Poems"},"诗歌":{zh:"诗歌",en:"Poems"},"Prose":{zh:"散文",en:"Prose"},"散文":{zh:"散文",en:"Prose"},"第七层":{zh:"第七层",en:"7th Floor"},"7th Floor":{zh:"第七层",en:"7th Floor"},"Life":{zh:"生活",en:"Life"},"生活":{zh:"生活",en:"Life"},"Tech":{zh:"科技",en:"Tech"},"科技":{zh:"科技",en:"Tech"},"技术":{zh:"技术",en:"Tech"},"Art":{zh:"艺术",en:"Art"},"艺术":{zh:"艺术",en:"Art"},"Fiction":{zh:"小说",en:"Fiction"},"Poetry":{zh:"诗歌",en:"Poetry"},"Essay":{zh:"散文",en:"Essay"},"Essays":{zh:"散文",en:"Essays"},"随笔":{zh:"随笔",en:"Musings"},"笔记":{zh:"笔记",en:"Notes"},"Notes":{zh:"笔记",en:"Notes"},"日记":{zh:"日记",en:"Diary"},"Diary":{zh:"日记",en:"Diary"},"翻译":{zh:"翻译",en:"Translation"},"Translation":{zh:"翻译",en:"Translation"},"书评":{zh:"书评",en:"Book Reviews"},"读书":{zh:"读书",en:"Reading"},"Reading":{zh:"读书",en:"Reading"},"Reviews":{zh:"评论",en:"Reviews"},"评论":{zh:"评论",en:"Reviews"},"摄影":{zh:"摄影",en:"Photography"},"Photography":{zh:"摄影",en:"Photography"},"旅行":{zh:"旅行",en:"Travel"},"Travel":{zh:"旅行",en:"Travel"},"美食":{zh:"美食",en:"Food"},"Food":{zh:"美食",en:"Food"},"音乐":{zh:"音乐",en:"Music"},"Music":{zh:"音乐",en:"Music"},"电影":{zh:"电影",en:"Films"},"Film":{zh:"电影",en:"Films"},"Movies":{zh:"电影",en:"Movies"},"编程":{zh:"编程",en:"Programming"},"Programming":{zh:"编程",en:"Programming"},"Code":{zh:"代码",en:"Code"},"设计":{zh:"设计",en:"Design"},"Design":{zh:"设计",en:"Design"},"AI":{zh:"AI",en:"AI"},"教程":{zh:"教程",en:"Tutorials"},"Tutorial":{zh:"教程",en:"Tutorial"},"思考":{zh:"思考",en:"Thoughts"},"Thoughts":{zh:"思考",en:"Thoughts"},"随想":{zh:"随想",en:"Reflections"}};function getTranslations(rawTag){return navDictionary[rawTag]||{zh:rawTag,en:rawTag};}
function translateTagsIn(root){root.querySelectorAll('.translatable-tag').forEach(link=>{const rawTag=link.getAttribute('data-raw-tag');if(!rawTag)return;const trans=getTranslations(rawTag);const zhSpan=link.querySelector('.lang-zh');const enSpan=link.querySelector('.lang-en');if(zhSpan)zhSpan.textContent=trans.zh;if(enSpan)enSpan.textContent=trans.en;});}
translateTagsIn(document);window.__rinuanPostProcess=function(root){adjustPostTypography(root);translateTagsIn(root);};(function(){if(document.querySelector('.post-body.full-content'))return;const list=document.querySelector('.blog-posts');const pager=document.querySelector('.blog-pager');const firstOlder=pager&&pager.querySelector('a.older-link');if(!list||!firstOlder)return;let nextUrl=firstOlder.getAttribute('href');let loading=false,ended=false;pager.style.display='none';const keyOf=post=>{const a=post.querySelector('h2.post-title a, a.read-more');return a?(a.getAttribute('href')||''):'';};const seen={};list.querySelectorAll('.post-outer').forEach(p=>{const k=keyOf(p);if(k)seen[k]=1;});const L=(zh,en)=>'<span class="lang-zh">'+zh+'</span><span class="lang-en">'+en+'</span>';const sentinel=document.createElement('div');sentinel.className='infinite-sentinel';const status=document.createElement('div');status.className='infinite-status';list.after(sentinel,status);const setStatus=html=>{status.innerHTML=html;status.classList.add('is-visible');};const showEnd=()=>setStatus('<span class="end-dingbat">···</span>');const showError=()=>{setStatus(L('加载出错','Couldn’t load')+'<button type="button" class="retry-btn">'+L('重试','Retry')+'</button>');status.querySelector('.retry-btn').addEventListener('click',()=>{status.classList.remove('is-visible');load();});};const load=()=>{if(loading||ended||!nextUrl)return;loading=true;setStatus('<span class="loading-dot"></span>');fetch(nextUrl,{credentials:'same-origin'}).then(r=>{if(!r.ok)throw 0;return r.text();}).then(html=>{const doc=new DOMParser().parseFromString(html,'text/html');const tmp=document.createElement('div');doc.querySelectorAll('.blog-posts .post-outer').forEach(p=>{const k=keyOf(p);if(k&&seen[k])return;if(k)seen[k]=1;tmp.appendChild(document.importNode(p,true));});if(window.__rinuanPostProcess)window.__rinuanPostProcess(tmp);if(window.__rinuanToVariant)window.__rinuanToVariant(tmp);while(tmp.firstChild)list.appendChild(tmp.firstChild);const older=doc.querySelector('.blog-pager a.older-link');nextUrl=older?older.getAttribute('href'):null;loading=false;if(nextUrl)status.classList.remove('is-visible');else{ended=true;showEnd();}}).catch(()=>{loading=false;showError();});};if('IntersectionObserver'in window){new IntersectionObserver(entries=>{if(entries[0].isIntersecting)load();},{rootMargin:'600px 0px'}).observe(sentinel);}else{pager.style.display='';sentinel.remove();status.remove();}})();});
