(function(){'use strict';const TEXT_REPLY='<span class="lang-zh"><span class="variant-simp">回复</span><span class="variant-trad">回覆</span></span><span class="lang-en">Reply</span>';const TEXT_CANCEL='<span class="lang-zh"><span class="variant-simp">取消回复</span><span class="variant-trad">取消回覆</span></span><span class="lang-en">Cancel</span>';const TEXT_WRITE='<span class="lang-zh"><span class="variant-simp">写留言</span><span class="variant-trad">寫留言</span></span><span class="lang-en">Write a comment</span>';const TEXT_COLLAPSE='<span class="lang-zh"><span class="variant-simp">收起留言框</span><span class="variant-trad">收起留言框</span></span><span class="lang-en">Collapse comment box</span>';const TEXT_DELETE='<span class="lang-zh"><span class="variant-simp">删除</span><span class="variant-trad">刪除</span></span><span class="lang-en">Delete</span>';function initFormLifecycle(){const commentToggleBtn=document.getElementById("comment-toggle");const commentsWrapper=document.querySelector(".comments-wrapper");const customFormContainer=document.getElementById("custom-comment-form-container");if(!commentsWrapper||!customFormContainer)return;function initializeCommentIframe(){const editorIframe=document.getElementById("comment-editor");if(!editorIframe)return false;const formInner=document.createElement('div');formInner.className='form-inner';formInner.appendChild(editorIframe);customFormContainer.appendChild(formInner);commentsWrapper.classList.add("show-main-form");customFormContainer.classList.add("is-expanded");if(commentToggleBtn)commentToggleBtn.innerHTML=TEXT_COLLAPSE;return true;}
if(!initializeCommentIframe()){const iframeObserver=new MutationObserver(()=>{if(initializeCommentIframe())iframeObserver.disconnect();});iframeObserver.observe(commentsWrapper,{childList:true,subtree:true});setTimeout(()=>iframeObserver.disconnect(),8000);}
if(commentToggleBtn){commentToggleBtn.addEventListener("click",e=>{e.preventDefault();const editorIframe=document.getElementById("comment-editor");const isExpanded=commentsWrapper.classList.contains("show-main-form");document.querySelectorAll(".comment-reply.cancel-active").forEach(btn=>{btn.classList.remove("cancel-active");btn.innerHTML=TEXT_REPLY;});if(isExpanded){commentsWrapper.classList.remove("show-main-form");commentToggleBtn.innerHTML=TEXT_WRITE;customFormContainer.classList.remove("is-expanded");}else{const mainComments=document.getElementById("comments");const formInner=customFormContainer.querySelector('.form-inner');const srcLink=document.getElementById("comment-editor-src");const wasExpanded=customFormContainer.classList.contains("is-expanded");const alreadyAtTop=customFormContainer.parentNode===commentsWrapper&&customFormContainer.nextSibling===mainComments;const relocateAndExpand=()=>{if(mainComments&&!alreadyAtTop){commentsWrapper.insertBefore(customFormContainer,mainComments);}
if(editorIframe&&formInner&&!formInner.contains(editorIframe)){formInner.appendChild(editorIframe);}
