let restructureTimer;function restructureComments(){document.querySelectorAll(".avatar-image-container img:not([data-hires])").forEach(img=>{const src=img.getAttribute("src");if(!src)return;const isReply=!!img.closest(".comment-replies");const target=isReply?"s48-c":"s80-c";const updated=src.replace(/\/s\d+(-c)?\//,"/"+target+"/").replace(/=s\d+(-c)?(?=$|[&?])/,"="+target);if(updated!==src)img.setAttribute("src",updated);img.dataset.hires="true";});document.querySelectorAll(".item-control a:not([data-cleaned-del])").forEach(btn=>{const lowerText=btn.innerText.trim().toLowerCase();if(lowerText==="delete"||lowerText==="删除"){btn.innerHTML=TEXT_DELETE;btn.dataset.cleanedDel="true";}});document.querySelectorAll(".comment:not([data-cleaned])").forEach(comment=>{const controls=comment.querySelector(".item-control");const replyBtns=comment.querySelectorAll(".comment-reply");if(controls&&replyBtns.length){controls.appendChild(replyBtns[0]);replyBtns[0].style.display="inline-flex";replyBtns[0].innerHTML=replyBtns[0].classList.contains("cancel-active")?TEXT_CANCEL:TEXT_REPLY;for(let i=1;i<replyBtns.length;i++)replyBtns[i].remove();comment.dataset.cleaned="true";}});document.querySelectorAll(".comment-replies:not([data-folded])").forEach(thread=>{const ol=thread.querySelector("ol");const nestedComments=thread.querySelectorAll(".comment");if(!ol||nestedComments.length===0)return;const parentComment=thread.closest('.comment');if(parentComment&&!parentComment.querySelector(':scope > .thread-trunk')){const trunk=document.createElement('div');trunk.className='thread-trunk';parentComment.insertBefore(trunk,parentComment.firstChild);}
const wrapper=document.createElement("div");wrapper.className="replies-grid-wrapper";const inner=document.createElement("div");inner.className="replies-grid-inner";ol.parentNode.insertBefore(wrapper,ol);wrapper.appendChild(inner);inner.appendChild(ol);const toggleBtn=document.createElement("button");const hiddenCount=nestedComments.length;toggleBtn.className="reply-toggle-btn";toggleBtn.dataset.count=hiddenCount;const buildLabel=isExpanded=>{const arrowSvg='<svg viewBox="0 0 24 24"><path d="M7 10l5 5 5-5z"/></svg>';if(isExpanded){return arrowSvg+'<span class="lang-zh"><span class="variant-simp">收起回复</span><span class="variant-trad">收起回覆</span></span>'+'<span class="lang-en">Collapse replies</span>';}
const enText=hiddenCount===1?'reply':'replies';return arrowSvg+'<span class="lang-zh"><span class="variant-simp">'+hiddenCount+' 条回复</span><span class="variant-trad">'+hiddenCount+' 則回覆</span></span>'+'<span class="lang-en">'+hiddenCount+' '+enText+'</span>';};toggleBtn.innerHTML=buildLabel(false);toggleBtn.onclick=e=>{e.preventDefault();const isExpanded=toggleBtn.classList.contains("expanded");wrapper.classList.toggle("is-expanded",!isExpanded);toggleBtn.classList.toggle("expanded");toggleBtn.innerHTML=buildLabel(!isExpanded);};if(wrapper.nextSibling){wrapper.parentNode.insertBefore(toggleBtn,wrapper.nextSibling);}else{wrapper.parentNode.appendChild(toggleBtn);}
thread.dataset.folded="true";});document.querySelectorAll(".comment-replies .comment:not([data-branched])").forEach(childComment=>{const branch=document.createElement('div');branch.className='yt-branch';childComment.insertBefore(branch,childComment.firstChild);childComment.dataset.branched="true";});const wrapper=document.querySelector(".comments-wrapper");if(wrapper){wrapper.querySelectorAll("a, span").forEach(el=>{const lowerText=el.innerText.trim().toLowerCase();if(lowerText==="load more..."||lowerText.includes("load more"))el.remove();});}}
const commentObserver=new MutationObserver(()=>{clearTimeout(restructureTimer);restructureTimer=setTimeout(restructureComments,16);});function startObserving(){const container=document.getElementById("comments")||document.querySelector(".comments-wrapper");if(container)commentObserver.observe(container,{childList:true,subtree:true});}
